import React, { useEffect, useRef, useState } from 'react';
import {
  Container, Box, Paper, Typography, Button, Select, MenuItem, FormControl, InputLabel, TextField, CircularProgress, Chip
} from '@mui/material';
import { Code, Mic, PlayArrow, Save, ContentCopy } from '@mui/icons-material';
import { Editor } from '@monaco-editor/react';
import apiService from '../services/apiService';
import { useVoiceControl } from '../context/VoiceControlContext';
import VoiceControl from '../VoiceControl';

const CodeGenerationPage = () => {
  const [transcript, setTranscript] = useState('');
  const [manualPrompt, setManualPrompt] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const [compileOutput, setCompileOutput] = useState('');
  const [userInput, setUserInput] = useState('');
  const [micLoading, setMicLoading] = useState(false);
  const [generateLoading, setGenerateLoading] = useState(false);
  const [compileLoading, setCompileLoading] = useState(false);
  const [recording, setRecording] = useState(false);
  const [language, setLanguage] = useState('python');

  const transcriptEndRef = useRef(null);
  const codeEndRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);

  const speak = (text) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const startRecording = async () => {
    if (recording) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await handleTranscribe(audioBlob);
      };

      mediaRecorder.start();
      setRecording(true);
      speak('Recording started');
    } catch (err) {
      setTranscript('Microphone access denied or not available');
    }
  };

  const stopRecording = () => {
    if (recording && mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setRecording(false);
    }
  };

  const handleTranscribe = async (audioBlob) => {
    setMicLoading(true);
    try {
      const res = await apiService.transcribeAudio(audioBlob);
      if (res.transcript) {
        setTranscript((prev) => (prev ? prev + ' ' + res.transcript : res.transcript));
      } else if (res.error) {
        setTranscript('❌ ' + res.error);
        speak('Error transcribing audio.');
      } else {
        setTranscript('❌ No transcript received.');
        speak('No transcript received.');
      }
    } catch (err) {
      console.error(err);
      setTranscript('❌ Error transcribing audio.');
      speak('Error transcribing audio.');
    }
    setMicLoading(false);
  };

  const handleGenerateCode = async () => {
    const promptToSend = transcript.trim() || manualPrompt.trim();
    if (!promptToSend) return;
    setGenerateLoading(true);
    try {
      const res = await apiService.generateCode(promptToSend, language);
      setGeneratedCode(res.code || '// No code generated');
      speak('Code generated successfully.');
    } catch (err) {
      console.error(err);
      setGeneratedCode('// Error generating code');
      speak('Error generating code.');
    }
    setGenerateLoading(false);
  };

  const handleCompile = async () => {
    if (!generatedCode) return;
    setCompileLoading(true);
    try {
      const res = await apiService.compileCode(generatedCode, language, userInput);
      const output = res.stdout || res.stderr || res.compile_output || '// No output received';
      setCompileOutput(output);
      speak('Compilation finished.');
    } catch (err) {
      console.error(err);
      setCompileOutput('// Error compiling code');
      speak('Error compiling code.');
    }
    setCompileLoading(false);
  };

  const handleSaveFile = () => {
    const blob = new Blob([generatedCode], { type: 'text/plain' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'generated_code.' + (language === 'python' ? 'py' : language === 'javascript' ? 'js' : language === 'java' ? 'java' : 'txt');
    a.click();
    window.URL.revokeObjectURL(url);
    speak('File saved successfully.');
  };

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [transcript]);

  useEffect(() => {
    codeEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [generatedCode, compileOutput]);

  return (
    <Container maxWidth="lg">
      <VoiceControl
        isRecording={recording}
        onTranscriptChange={setTranscript}
        onStartRecording={startRecording}
        onStopRecording={stopRecording}
        onGenerateCode={handleGenerateCode}
        onCompileCode={handleCompile}
        onSaveCode={handleSaveFile}
        onCopyCode={() => {
          if (generatedCode) {
            navigator.clipboard.writeText(generatedCode);
            speak('Code copied to clipboard');
          }
        }}
      />
      <Box sx={{ mt: 4 }}>
        <Typography variant="h4" component="h1" gutterBottom>
          Code Generation
        </Typography>

        <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
          <FormControl sx={{ minWidth: 200 }}>
            <InputLabel>Language</InputLabel>
            <Select value={language} label="Language" onChange={(e) => setLanguage(e.target.value)}>
              <MenuItem value="python">Python</MenuItem>
              <MenuItem value="javascript">JavaScript</MenuItem>
              <MenuItem value="java">Java</MenuItem>
              <MenuItem value="cpp">C++</MenuItem>
              <MenuItem value="c">C</MenuItem>
            </Select>
          </FormControl>
          <Button onClick={recording ? stopRecording : startRecording} variant="contained" color={recording ? 'error' : 'primary'} disabled={micLoading}>
            {recording ? 'Stop Recording' : 'Start Recording'}
          </Button>
        </Box>

        <TextField
          label="Transcript / Problem statement"
          value={transcript}
          onChange={(e) => setTranscript(e.target.value)}
          fullWidth
          multiline
          minRows={3}
        />

        <TextField
          label="Or type your prompt"
          value={manualPrompt}
          onChange={(e) => setManualPrompt(e.target.value)}
          fullWidth
          sx={{ mt: 2 }}
        />

        <Button onClick={handleGenerateCode} disabled={generateLoading} variant="contained" sx={{ mt: 2 }}>
          {generateLoading ? <><CircularProgress size={18} sx={{ mr: 1 }} /> Generating...</> : 'Generate Code'}
        </Button>

        <Paper sx={{ mt: 3, p: 1 }}>
          <Editor
            height="40vh"
            defaultLanguage={language === 'cpp' ? 'cpp' : language}
            value={generatedCode}
            onChange={(value) => setGeneratedCode(value || '')}
            options={{ minimap: { enabled: false } }}
          />
          <Box sx={{ display: 'flex', gap: 1, mt: 1 }}>
            <Button onClick={() => navigator.clipboard.writeText(generatedCode)} disabled={!generatedCode}>
              Copy
            </Button>
            <Button onClick={handleSaveFile} disabled={!generatedCode}>Save</Button>
          </Box>
        </Paper>

        <TextField
          label="Program Input (stdin)"
          value={userInput}
          onChange={(e) => setUserInput(e.target.value)}
          fullWidth
          multiline
          minRows={3}
          sx={{ mt: 2 }}
        />

        <Button onClick={handleCompile} disabled={compileLoading || !generatedCode} variant="outlined" sx={{ mt: 2 }}>
          {compileLoading ? <><CircularProgress size={18} sx={{ mr: 1 }} /> Running...</> : 'Compile & Run'}
        </Button>

        <Paper sx={{ mt: 2, p: 2, backgroundColor: '#111' }}>
          <Typography variant="subtitle2" gutterBottom>Program Output</Typography>
          <pre style={{ margin: 0, color: '#8f8' }}>{compileOutput || '// Output will appear here'}</pre>
          <div ref={codeEndRef} />
        </Paper>
      </Box>
    </Container>
  );
};

export default CodeGenerationPage;
